+        parsedData.phone, 
+        parsedData.disc, 
+        parsedData.notes, 
+        parsedData.questions, 
+        parsedData.mbti,
+        'PENDING'
+      );
+
+      const { error } = await supabase
+        .from('applications')
+        .update({ candidate_phone: updatedPhoneVal })
+        .eq('id', appId);
